**store.ts**:
```ts
import type { PetData } from './types';
const KEY = 'pixel-pets-v1';

export function savePets(pets: { toData(): PetData }[]): void {
  localStorage.setItem(KEY, JSON.stringify(pets.map(p => p.toData())));
}

export function loadPetData(): PetData[] {
  try {
    const raw = localStorage.getItem(KEY);
    return raw ? (JSON.parse(raw) as PetData[]) : [];
  } catch { return []; }
}
```

**pet.ts additions**:
- onHungerChange?: () => void — called when hunger crosses an integer boundary
- Hunger decay in update(): this.hunger = Math.max(0, this.hunger - 2 * dt / 60); call onHungerChange when Math.floor changes
- Pet does NOT import store.ts

**main.ts changes**:
```ts
import { loadPetData, savePets } from './store';

function makePet(data: PetData): Pet {
  const p = new Pet(data);
  p.onTransition = () => savePets(pets);
  p.onHungerChange = () => savePets(pets);
  return p;
}

let pets: Pet[] = loadPetData().map(makePet);
if (pets.length === 0) {
  pets = [makePet({ id: crypto.randomUUID(), name: 'Rex', type: 'dog', color: 'brown', x: 200, y: 0, hunger: 100 })];
}
```

